import React, { useState } from 'react';

const FarmerAdd = () => {
  const [step, setStep] = useState(1);
  
  return (
    <div className="p-6">
      <div className="flex justify-between mb-8">
        {[1, 2, 3].map(s => (
          <div key={s} className={`h-4 w-1/4 rounded-full ${step >= s ? 'bg-green-600' : 'bg-gray-300'}`} />
        ))}
      </div>

      {step === 1 && (
        <div className="text-center">
          <h2 className="text-3xl font-bold mb-6">Take Photo</h2>
          <div className="w-full h-64 bg-gray-200 rounded-3xl border-4 border-dashed border-gray-400 flex items-center justify-center text-6xl">
            📸
          </div>
          <button onClick={() => setStep(2)} className="w-full mt-8 bg-green-600 text-white py-6 rounded-2xl text-2xl font-bold">Next</button>
        </div>
      )}

      {step === 2 && (
        <div>
          <h2 className="text-3xl font-bold mb-6">How much? (Weight)</h2>
          <input type="text" placeholder="e.g. 50 kg" className="w-full p-8 text-4xl rounded-2xl border-4 border-green-600 mb-6" />
          <button onClick={() => setStep(3)} className="w-full bg-green-600 text-white py-6 rounded-2xl text-2xl font-bold">Next</button>
        </div>
      )}

      {step === 3 && (
        <div>
          <h2 className="text-3xl font-bold mb-6">Set Price</h2>
          <input type="text" placeholder="₹ Price" className="w-full p-8 text-4xl rounded-2xl border-4 border-green-600 mb-6" />
          <button className="w-full bg-orange-500 text-white py-6 rounded-2xl text-2xl font-bold shadow-lg">FINISH & SELL</button>
        </div>
      )}
    </div>
  );
};
